// [#protodoc-title: Custom Header Injection Filter]
//
// The configuration for the Custom Header Injection filter that injects
// configurable headers into requests and/or responses.
//
// [#extension: envoy.filters.http.custom_header_injection]

message Config {
  // Header injection rule for adding headers to requests or responses.
  message HeaderInjection {
    // The header name to inject.
    string header_name = 1 [(validate.rules).string = {min_len: 1}];

    // The header value to inject.
    string header_value = 2;
  }

  // Headers to inject into requests.
  repeated HeaderInjection request_headers = 1;

  // Headers to inject into responses.
  repeated HeaderInjection response_headers = 2;
